-------------------------
CONTENT GUIDELINES
-------------------------

- Match the brand’s natural voice. Infer tone from the research data — do NOT default to any single style.
- For each section, add 1–2 sentences of narrative context, not just bullets.
- Use concrete details (time, format, channels) specific to the client’s industry and audience.
- For ICPs, write vivid “before state” paragraphs plus exact phrases in their own array.
- For vertical_language, generate categories dynamically based on the client’s actual industry (e.g. “emergency_repair”, “preventive_maintenance” for a plumber; “onboarding”, “churn_prevention” for SaaS).
- For visual_identity, infer from company_intelligence and research data; if specifics are missing, leave fields empty rather than fabricating.

-------------------------
RULES
-------------------------

- Output ONLY the JSON object, nothing before or after.
- It MUST parse with JSON.parse with no errors.
- No comments, no trailing commas, no Markdown.

parameters.jsCode:
// 1) Parse input JSON from previous agent
const raw = items[0].json.output || "{}";
let root;
try {
  root = typeof raw === "string" ? JSON.parse(raw) : raw;
} catch (e) {
  root = { parse_error: String(e), raw };
}

// Escape helper for HTML safety
function esc(str) {
  return String(str ?? "").replace(/&/g, "&amp;")
                          .replace(/</g, "&lt;")
                          .replace(/>/g, "&gt;");
}

function asArray(v) {
  return Array.isArray(v) ? v : [];
}

// ==========================
// RENDER HELPERS FOR SECTIONS
// ==========================

function renderValuesTable(values) {
  const rows = asArray(values);
  if (!rows.length) return "";
  return `
  <table>
    <thead>
      <tr>
        <th>Value</th>
        <th>What it means</th>
        <th>How it shows up</th>
      </tr>
    </thead>
    <tbody>
      ${rows.map(v => `
        <tr>
          <td><strong>${esc(v.value)}</strong></td>
          <td>${esc(v.what_it_means)}</td>
          <td>${esc(v.how_it_shows_up)}</td>
        </tr>
      `).join("")}
    </tbody>
  </table>`;
}

function renderToneTable(rowsIn) {
  const rows = asArray(rowsIn);
  if (!rows.length) return "";
  return `
  <table>
    <thead>
      <tr>
        <th>Tone Dimension</th>
        <th>What it sounds like</th>
        <th>What it doesn't sound like</th>
      </tr>
    </thead>
    <tbody>
      ${rows.map(r => `
        <tr>
          <td><strong>${esc(r.dimension)}</strong></td>
          <td>${esc(r.sounds_like)}</td>
          <td>${esc(r.does_not_sound_like)}</td>
        </tr>
      `).join("")}
    </tbody>
  </table>`;
}

// Pull-quote block for “exact words”
function renderPullQuote(linesIn) {
  const lines = asArray(linesIn);
  if (!lines.length) return "";
  return `
  <div class="pull-quote">
    ${lines.map(l => `<p>${esc(l)}</p>`).join("")}
  </div>`;
}

function renderICPs(icpsIn) {
  const icps = asArray(icpsIn);
  if (!icps.length) return "";
  return `
<section>
  <h1>04 Ideal Customer Profiles (ICPs) & Audience</h1>
  <p class="section-intro">Detailed audience snapshots with their real language, objections, and what moves them to action.</p>
  ${icps.map(icp => {
    const attrs = asArray(icp.attributes_table).map(a => `
      <tr>
        <td><strong>${esc(a.attribute)}</strong></td>
        <td>${esc(a.details)}</td>
      </tr>
    `).join("");
    const wwmtb = asArray(icp.what_would_make_them_buy).map(w => `<li>${esc(w)}</li>`).join("");
    const crit = asArray(icp.decision_criteria).map(w => `<li>${esc(w)}</li>`).join("");
    const trig = asArray(icp.trigger_events).map(w => `<li>${esc(w)}</li>`).join("");
    return `
    <section class="icp-block">
      ${icp.id ? `<div class="eyebrow">${esc(icp.id)}</div>` : ""}
      <h2>${esc(icp.name || "")}${icp.label ? " — " + esc(icp.label) : ""}</h2>
      ${attrs ? `
      <table>
        <thead><tr><th>Profile Attribute</th><th>Details</th></tr></thead>
        <tbody>${attrs}</tbody>
      </table>` : ""}
      <h3>Before State — Exact Reality</h3>
      <p>${esc(icp.before_state)}</p>
      <h3>Their Exact Words</h3>
      ${renderPullQuote(icp.exact_words)}
      <h3>What They Actually Want</h3>
      <p>${esc(icp.what_they_actually_want)}</p>
      <h3>Primary Objection</h3>
      <p>${esc(icp.primary_objection)}</p>
      <h3>What Would Make Them Buy</h3>
      <ul>${wwmtb}</ul>
      <div class="callout info">
        <div class="callout-title">Viewpoint Shift Card</div>
        <p>${esc(icp.viewpoint_shift_prompt)}</p>
      </div>
      <h3>Decision Criteria</h3>
      <ul>${crit}</ul>
      <h3>Trigger Events</h3>
      <ul>${trig}</ul>
    </section>`;
  }).join("")}
</section>`;
}

function renderButtons(b) {
  if (!b) return "";
  const painItems = asArray(b.pain_buttons?.items);
  const desireItems = asArray(b.desire_buttons?.items);
  const obsItems = asArray(b.objections);

  const pain = painItems.map(x => `
    <tr>
      <td>#${esc((x.rank ?? 0) + 1)}</td>
      <td>${esc(x.segment)}</td>
      <td>${esc(x.button)}</td>
      <td><ul>${asArray(x.exact_phrases).map(p => `<li>${esc(p)}</li>`).join("")}</ul></td>
    </tr>
  `).join("");

  const desire = desireItems.map(x => `
    <tr>
      <td>#${esc((x.rank ?? 0) + 1)}</td>
      <td>${esc(x.segment)}</td>
      <td>${esc(x.button)}</td>
      <td><ul>${asArray(x.exact_phrases).map(p => `<li>${esc(p)}</li>`).join("")}</ul></td>
    </tr>
  `).join("");

  const obs = obsItems.map(o => `
    <tr>
      <td>${esc(o.objection)}</td>
      <td><ul>${asArray(o.exact_words).map(w => `<li>${esc(w)}</li>`).join("")}</ul></td>
      <td>${esc(o.how_to_handle)}</td>
    </tr>
  `).join("");

  return `
<section>
  <h1>05 Buttons & Objections (Survey-Driven)</h1>
  <p class="section-intro">Real phrases and majority-agreement buttons to open every campaign with instant resonance.</p>
  <h2>Pain Buttons</h2>
  ${pain ? `
  <table>
    <thead><tr><th>Rank</th><th>Segment</th><th>Button</th><th>Exact phrases</th></tr></thead>
    <tbody>${pain}</tbody>
  </table>` : "<p class='muted'>No pain buttons available.</p>"}
  <h2>Desire Buttons</h2>
  ${desire ? `
  <table>
    <thead><tr><th>Rank</th><th>Segment</th><th>Button</th><th>Exact phrases</th></tr></thead>
    <tbody>${desire}</tbody>
  </table>` : "<p class='muted'>No desire buttons available.</p>"}
  <h2>Objections</h2>
  ${obs ? `
  <table>
    <thead><tr><th>Objection</th><th>Exact words</th><th>How to handle</th></tr></thead>
    <tbody>${obs}</tbody>
  </table>` : "<p class='muted'>No objections captured.</p>"}
</section>`;
}

function renderLanguageLibrary(lang) {
  if (!lang) return '';

  const usePain = asArray(lang.use_pain);
  const useDesire = asArray(lang.use_desire);
  const termsToUse = asArray(lang.terms_to_use);
  const avoid = asArray(lang.avoid);
  const vertical = asArray(lang.vertical_language);

  let html = 'section';
  html += '<h1>06 Language Library & Terminology</h1>';
  html += '<p class="section-intro">Use this library to keep every asset on-message — same pain, same desire, same phrases.</p>';

  // Language to USE – Pain / Problem
  html += '<h2>Language to USE – Pain / Problem</h2>';
  if (usePain.length) {
    html += '<ul>' + usePain.map(x => `<li>${esc(x)}</li>`).join('') + '</ul>';
  } else {
    html += '<p class="muted">No pain-focused language defined.</p>';
  }

  // Language to USE – Desire / Solution
  html += '<h2>Language to USE – Desire / Solution</h2>';
  if (useDesire.length) {
    html += '<ul>' + useDesire.map(x => `<li>${esc(x)}</li>`).join('') + '</ul>';
  } else {
    html += '<p class="muted">No desire-focused language defined.</p>';
  }

  // Terms to USE
  html += '<h2>Terms to USE</h2>';
  if (termsToUse.length) {
    html += '<table><thead><tr><th>Term</th><th>How to use it</th></tr></thead><tbody>';
    html += termsToUse.map(t =>
      `<tr><td><strong>${esc(t.term || '')}</strong></td><td>${esc(t.how_to_use || '')}</td></tr>`
    ).join('');
    html += '</tbody></table>';
  } else {
    html += '<p class="muted">No specific terms defined.</p>';
  }

  // Words/Phrases to AVOID
  html += '<h2>Words/Phrases to AVOID</h2>';
  if (avoid.length) {
    html += '<table><thead><tr><th>Avoid this</th><th>Reason why</th></tr></thead><tbody>';
    html += avoid.map(a =>
      `<tr><td><strong>${esc(a.term || '')}</strong></td><td>${esc(a.reason || '')}</td></tr>`
    ).join('');
    html += '</tbody></table>';
  } else {
    html += '<p class="muted">No explicit avoid list defined.</p>';
  }

  // Vertical Language (dynamic array)
  if (vertical.length) {
    html += '<div class="callout subtle">';
    html += '<div class="callout-title">Vertical Language Guidance</div>';
    vertical.forEach(v => {
      html += `<h3>${esc(v.category || '')}</h3>`;
      html += `<p><strong>Use:</strong> ${esc(v.use || '')}</p>`;
      html += `<p><strong>Context:</strong> ${esc(v.context || '')}</p>`;
      html += `<p><strong>Power phrase:</strong> ${esc(v.power_phrase || '')}</p>`;
    });
    html += '</div>';
  }

  html += 'section';
  return html;
}

function renderOfferArchitecture(off) {
  if (!off) return "";

  const offerStackRows = asArray(off.offer_stack).map(o => `
    <tr>
      <td><strong>${esc(o.tier)}</strong></td>
      <td>${esc(o.what_they_get)}</td>
      <td>${esc(o.price_or_commitment)}</td>
      <td>${esc(o.cta)}</td>
    </tr>
  `).join("");

  const valueFactors = asArray(off.value_equation).map(v => `
    <tr>
      <td><strong>${esc(v.factor)}</strong></td>
      <td>${esc(v.market_standard)}</td>
      <td>${esc(v.optimized)}</td>
    </tr>
  `).join("");

  const funnelSteps = asArray(off.funnel?.steps).map(s => `
    <tr>
      <td><strong>${esc(s.stage)}</strong></td>
      <td>${esc(s.asset)}</td>
      <td>${esc(s.goal)}</td>
      <td>${esc(s.next_step)}</td>
    </tr>
  `).join("");

  const pricingRows = asArray(off.pricing_tiers).map(p => `
    <tr>
      <td><strong>${esc(p.name)}</strong></td>
      <td>${esc(p.price)}</td>
      <td>${esc(p.who_its_for)}</td>
      <td><ul>${asArray(p.features).map(f => `<li>${esc(f)}</li>`).join("")}</ul></td>
    </tr>
  `).join("");

  return `
<section>
  <h1>07 Offer Architecture & Funnel</h1>
  <p class="section-intro">How we package the value: from free uplift to deep practice and partner support.</p>
  <div class="callout primary">
    <div class="callout-title">Core Offer Statement</div>
    <p>${esc(off.core_offer_statement)}</p>
  </div>

  <h2>Offer Stack</h2>
  ${offerStackRows ? `
  <table>
    <thead><tr><th>Tier</th><th>What They Get</th><th>Price/Commitment</th><th>CTA</th></tr></thead>
    <tbody>${offerStackRows}</tbody>
  </table>` : "<p class='muted'>No offer stack defined.</p>"}

  <h2>Value Equation</h2>
  ${valueFactors ? `
  <table>
    <thead><tr><th>Factor</th><th>Market Standard</th><th>Optimized</th></tr></thead>
    <tbody>${valueFactors}</tbody>
  </table>` : "<p class='muted'>No value equation factors listed.</p>"}

  ${off.guarantee ? `
  <div class="callout soft">
    <div class="callout-title">Guarantee</div>
    <p><strong>${esc(off.guarantee.type)}</strong></p>
    <p>${esc(off.guarantee.statement)}</p>
    <p><strong>Duration (days):</strong> ${esc(off.guarantee.duration_days)}</p>
    <p><strong>Conditions:</strong> ${esc(off.guarantee.conditions)}</p>
    <p><strong>Process:</strong> ${esc(off.guarantee.process)}</p>
  </div>
  ` : ''}

  ${pricingRows ? `
  <h2>Pricing Tiers</h2>
  <table>
    <thead><tr><th>Tier</th><th>Price</th><th>Who it's for</th><th>Features</th></tr></thead>
    <tbody>${pricingRows}</tbody>
  </table>` : ""}

  ${funnelSteps ? `
  <h2>Funnel Architecture</h2>
  <table>
    <thead><tr><th>Stage</th><th>Asset</th><th>Goal</th><th>Next Step</th></tr></thead>
    <tbody>${funnelSteps}</tbody>
  </table>` : ""}

  ${asArray(off.scarcity_rules).length ? `
  <h2>Scarcity & Urgency Rules</h2>
  <ul>${asArray(off.scarcity_rules).map(r => `<li>${esc(r)}</li>`).join("")}</ul>
  ` : ''}
</section>`;
}

function renderVisualIdentity(vis) {
  if (!vis) return "";

  const colorRows = asArray(vis.colors).map(c => `
    <tr>
      <td><strong>${esc(c.name)}</strong></td>
      <td>
        <span class="color-chip" style="background:${esc(c.hex)};"></span>
        ${esc(c.hex)}
      </td>
      <td>${esc(c.usage)}</td>
    </tr>
  `).join("");

  const typoRows = asArray(vis.typography).map(t => `
    <tr>
      <td><strong>${esc(t.element)}</strong></td>
      <td>${esc(t.typeface)}</td>
      <td>${esc(t.size_weight)}</td>
      <td>${esc(t.usage)}</td>
    </tr>
  `).join("");

  return `
<section>
  <h1>08 Visual Identity & Brand Assets</h1>
  <p class="section-intro">A simple visual system to keep everything feeling professional and trustworthy.</p>

  ${colorRows ? `
  <h2>Color Palette</h2>
  <table>
    <thead><tr><th>Color</th><th>Hex</th><th>Usage</th></tr></thead>
    <tbody>${colorRows}</tbody>
  </table>` : "<p class='muted'>No color palette defined.</p>"}

  ${typoRows ? `
  <h2>Typography</h2>
